<template id="TempSignIn">
  <b-row class="justify-content-md-center">
  	<b-col md="8">
  	<img src="../assets/quiz.png" alt="Firestore Quize App" class="app-logo">
    
	    <b-form @submit.prevent="onSubmit">
	        <b-form-group id="emailGroup"
                label="Email address:"
                label-for="email"
                description="We'll never share your email with anyone else.">
	        	<b-form-input id="email"
                  type="email"
                  v-model="email"
                  required
                  placeholder="Enter email">
	        </b-form-input>
	      </b-form-group>
	      
	        <b-form-group id="passwordGroup"
                label="Your Password:"
                label-for="password">
	        	<b-form-input id="password"
                  	type="password"
                  	v-model="password"
                  	required
                  	placeholder="Enter password">
	        	</b-form-input>
	        </b-form-group>
	     {{ error.message }}
        <b-button type="submit" variant="primary">SignIn</b-button>
       <b-link to="/signup">SignUp</b-link>
	    </b-form>
	</b-col>
  </b-row>
</template>
<script>
import firebase from 'firebase'
export default {
	name:'SignIn',
  	data () {
	    return {
	        email: '',
	        password: '',
          error:{}
	    }
  	},
  methods: {
    onSubmit () {
      firebase.auth().signInWithEmailAndPassword(this.email,this.password)
        .then((user) => {
          this.$router.push('/exam')
        })
        .catch(error => {
          console.log(error)
        })
    },
  }
}
</script>

<style scoped>
	
</style>



