<template id="TempSignIn">
  <div>Hello signPut</div>
</template>
<script>
import firebase from 'firebase'
export default {
	name:'SignOut',
  created(){
      firebase.auth().signOut().then(() =>{
        this.$router.push('/signin')
      }, function(error) {
        console.log('error in SignOut')
      });
    }
  }
</script>

