<template id="TempSignUp">
  <b-row class="justify-content-md-center">
  	<b-col md="8">
  	<img src="../assets/quiz.png" alt="Firestore Quize App" class="app-logo">
	    <b-form @submit.prevent="onSubmit">
	    	<b-form-group id="nameGroup"
	            label="Your Name:"
	            label-for="name">
	        	<b-form-input id="name"
	                type="text"
	                v-model="name"
	                required
	                placeholder="Enter Name">
	        	</b-form-input>
	        </b-form-group>

	        <b-form-group id="emailGroup"
                label="Email address:"
                label-for="email"
                description="We'll never share your email with anyone else.">
	        	<b-form-input id="email"
                  type="email"
                  v-model="email"
                  required
                  placeholder="Enter email">
	        </b-form-input>
	      </b-form-group>
	      
	        <b-form-group id="passwordGroup"
                label="Your Password:"
                label-for="password">
	        	<b-form-input id="password"
                  	type="password"
                  	v-model="password"
                  	required
                  	placeholder="Enter password">
	        	</b-form-input>
	        </b-form-group>
	        {{ error.message }}<br>
	      <b-button type="submit" variant="primary">SignUp</b-button>
	      	<b-link to="/signin">SignIn</b-link>
	    </b-form>
	</b-col>
  </b-row>
</template>
<script>
import firebase from 'firebase'
export default {
	name:'SignUp',
  	data () {
	    return {
	        email: '',
	        password: '',
	        name:'',
	        error:{}
	    }
  	},
  methods: {
    onSubmit () {
		firebase.auth().createUserWithEmailAndPassword(this.email,this.password)
			.then((user) => {
				user.updateProfile({
				  displayName: this.name,
				}).then(function() {
				  this.$router.push('/exam')
				}).catch(function(error) {
				  console.log(this.error)
				});
            })
	        .catch(error => {
	        this.error = error
		})
    },
  }
}
</script>

<style scoped>
	
</style>



