<template id="TempExam">
  <div>
    <b-row class="justify-content-md-center">
    	<b-col md="10" offset-md="1">
        <h1 class="text-center">Wellcome to exam room</h1>
        <b-card-group deck>
            <b-card bg-variant="primary"
              text-variant="white"
              header="Leaderboard"
              class="text-center">
              </b-card>
              <p>
                <ul>
                  <li v-for="participent in participents">
                    <span class="name">{{ participent.name}}</span>
                    <span class="point">{{ participent.score }}</span>
                  </li>
                </ul>
              </p>
        </b-card-group>
    	</b-col>
    </b-row>
    <b-row class="justify-content-md-left">
      <b-col md="8">
        <b-card :title="question.text" v-for="question in questions" :key="question.id">
            <p class="card-text">
              <b-form-group>
                <label class="custom-control custom-radio">
                  <input @change="submitAnswer('A',question.id)" :name="question.id" type="radio" class="custom-control-input">
                  <span class="custom-control-indicator"></span>
                  <span class="custom-control-description">{{ question.optionA }}</span>
                </label><br>
                <label class="custom-control custom-radio">
                  <input @change="submitAnswer('B',question.id)" :name="question.id" type="radio" class="custom-control-input">
                  <span class="custom-control-indicator"></span>
                  <span class="custom-control-description">{{ question.optionB }}</span>
                </label><br>
                <label class="custom-control custom-radio">
                  <input @change="submitAnswer('C',question.id)" :name="question.id" type="radio" class="custom-control-input">
                  <span class="custom-control-indicator"></span>
                  <span class="custom-control-description">{{ question.optionC }}</span>
                </label><br>
                <label class="custom-control custom-radio">
                  <input @change="submitAnswer('D',question.id)" :name="question.id" type="radio" class="custom-control-input">
                  <span class="custom-control-indicator"></span>
                  <span class="custom-control-description">{{ question.optionD }}</span>
                </label><br>
              </b-form-group>
            </p>
        </b-card>
      </b-col>
      
    </b-row>
  </div>
</template>
<script>
  
import { db } from '../main'
import firebase from 'firebase';
export default {
	name:'Exam',
  	data () {
	    return {
        questions:[],
        score : 0,
        participents:[],
        particiepent_id : ''
	    }
  	},
    firestore () {
      return {
        participents: db.collection('participents').orderBy('score')
      }
    },
  methods: {
    onSubmit () {
    },
    skipQuestion(){

    },
    submitAnswer(ans,id){
      this.questions.filter(question => {
        if(question.id == id){
          if(question.ans == ans){
            this.score +=1;
            db.collection('participents')
            .where('particiepent_id','==',this.particiepent_id)
            .get()
            .then(querySnapshot => {
              querySnapshot.forEach(doc => {
                doc.ref.update({
                  score : this.score,
                })
              })
            })
          }
        }
      })
    },
    scoreUpdate(id){

    },
  },
  computed: {
    
  },
  mounted() {
    
  },
  created(){
    db.collection('questions')
      .get()
      .then(querySnapshot => {
          querySnapshot.forEach(doc=>{
              const data = {
                'id' : doc.id,
                'text' : doc.data().question,
                'optionA' : doc.data().optionA,
                'optionB' : doc.data().optionB,
                'optionC' : doc.data().optionC,
                'optionD' : doc.data().optionD,
                'ans' : doc.data().ans,
              }
              this.questions.push(data)
              this.numberofQuestions++
          });
      })
      .catch(function(error) {
          console.log("Error getting documents: ", error);
      });

      const user = firebase.auth().currentUser;
      if (user) {
        console.log(user)
        const uid = user.uid;
        this.particiepent_id = user.uid
        const name = user.displayName;
        db.collection('participents').add({particiepent_id:uid, score:0, name:name})
      } else {
        this.$router.push('/signin')
      }



  }
}
</script>

<style scoped>
	ul > li{
    list-style: none;
  }
  .name{
    text-align: left;
  }
  .point{
    text-align: right;
    font-weight: 700;
  }
</style>



