<template id="TempAddQuestion">
  <b-row class="justify-content-md-center">
    <b-col md="8">
      <b-form @submit.prevent="addQuestion(question.question,
          question.optionA,
          question.optionB,
          question.optionC,
          question.optionD,
          question.ans)">
        <b-form-group id="questionGroup"
          label="Question:"
          label-for="question">
          <b-form-textarea id="question"
            v-model="question.question"
            placeholder="Enter question"
            :rows="3"
            :max-rows="6">
          </b-form-textarea>
          <label class="mr-sm-2" for="optionA">Option A</label>
          <b-form-input id="optionA"
            type="text"
            v-model="question.optionA"
            
            placeholder="Enter A Option">
          </b-form-input>
          <label class="mr-sm-2" for="optionB">Option B</label>
          <b-form-input id="optionB"
            type="text"
            v-model="question.optionB"
            
            placeholder="Enter A Option">
          </b-form-input>
          <label class="mr-sm-2" for="optionC">Option C</label>
          <b-form-input id="optionC"
            type="text"
            v-model="question.optionC"
            
            placeholder="Enter C Option">
          </b-form-input>
          <label class="mr-sm-2" for="optionD">Option D</label>
          <b-form-input id="optionD"
            type="text"
            v-model="question.optionD"
            
            placeholder="Enter D Option">
          </b-form-input>
          
          <label class="mr-sm-2" for="optionD">Correct Answer <code>{{ question.ans }}</code></label>
          <div class="input-group">
            <input type="radio" class="form-control" name="option" v-model="question.ans" value="A">
            {{question.optionA}}
          </div>
          <div class="input-group">
            <input type="radio" class="form-control" name="option" v-model="question.ans" value="B">
            {{ question.optionB }}
          </div>
          <div class="input-group">
            <input type="radio" class="form-control" name="option" v-model="question.ans" value="C">
            {{ question.optionC }}
          </div>
          <div class="input-group">
            <input type="radio" class="form-control" name="option" v-model="question.ans" value="D">
            {{ question.optionD }}
          </div>
        </b-form-group>
        <b-button type="submit" variant="primary">Add</b-button>
      </b-form>
    </b-col>
  </b-row>
</template>
<script>
import { db } from '../main'
  export default {
    name:'AddQuestion',
      data () {
        return {
          question:{}
        }
      },
    methods: { 
    addQuestion (question,optionA,optionB,optionC,optionD,ans)  {  
        db.collection('questions').add({question,optionA,optionB,optionC,optionD,ans})
      }
    }
  }
</script>
<style scoped>
</style>


