<template id="TempQuestions">
  <b-row class="justify-content-md-center">
  	<b-col md="10" offset-md="1">
      <div class="questions">
        <div class="question" v-for="question in questions">
          <p><b>Question: </b>{{ question.question }}</p>
            <ul>
              <li>{{ question.optionA }}</li>
              <li>{{ question.optionB }}</li>
              <li>{{ question.optionC }}</li>
              <li>{{ question.optionD }}</li>
            </ul>
            <p><b>Correct Ans: </b>{{ question.ans }}</p>
        </div>
      </div>
  	</b-col>
  </b-row>
</template>
<script>
import { db } from '../main'
export default {
	name:'Questions',
  	data () {
	    return {
	        questions:[]
	    }
  	},
  firestore () {
    return {
      questions: db.collection('questions').orderBy('question')
    }
  }
}
</script>

<style scoped>
	ul > li{
    list-style: none
  }
</style>



